// =============================================================================
// MPP-Pipeline-Setup.cs
// Self-contained WinForms installer for MPP Pipeline.
// PS2EXE is bundled directly - no internet connection required.
// Compiled by Build-Setup.bat using csc.exe (built into Windows).
//
// !! ICON REMINDER !!
// When you have a .ico file, update Build-Setup.bat to pass:
//   /win32icon:"C:\path\to\your.ico"
// to the csc.exe command, then rebuild.
// =============================================================================

using System;
using System.Diagnostics;
using System.Drawing;
using System.IO;
using System.Reflection;
using System.Text;
using System.Threading;
using System.Windows.Forms;

[assembly: AssemblyTitle("MPP Pipeline Setup")]
[assembly: AssemblyDescription("Installer for MPP Pipeline")]
[assembly: AssemblyCompany("SCI")]
[assembly: AssemblyProduct("MPP Pipeline")]
[assembly: AssemblyVersion("1.0.0.0")]

namespace MPPSetup
{
    static class Program
    {
        // ── Embedded MPP-Pipeline.ps1 ─────────────────────────────────────────
        internal const string APP_SOURCE_B64 = "";

        // ── Embedded PS2EXE module files ──────────────────────────────────────
        internal const string PS2EXE_PS1_B64    = "";
        internal const string PS2EXE_PSD1_B64   = "";
        internal const string PS2EXE_PSM1_B64   = "";
        internal const string PS2EXE_WINEXE_B64 = "";

        [STAThread]
        static void Main()
        {
            Application.EnableVisualStyles();
            Application.SetCompatibleTextRenderingDefault(false);
            Application.Run(new SetupForm());
        }
    }

    // =========================================================================
    // SETUP FORM
    // =========================================================================
    class SetupForm : Form
    {
        static readonly Color Navy    = Color.FromArgb(31, 78, 120);
        static readonly Color Green   = Color.FromArgb(20, 120, 40);
        static readonly Color BgLight = Color.FromArgb(245, 245, 248);
        static readonly Color Gray    = Color.FromArgb(80, 80, 100);

        Panel      pnlHeader, pnlBody, pnlFooter;
        Label      lblTitle, lblSubtitle, lblDirLabel, lblStatus, lblDetail, lblFooter;
        TextBox    tbInstallDir;
        Button     btnBrowse, btnInstall;
        ProgressBar pgBar;

        string installDir = System.Environment.GetFolderPath(System.Environment.SpecialFolder.LocalApplicationData) + "\\MPP Pipeline";
        bool   installing = false;

        public SetupForm() { BuildUI(); }

        void BuildUI()
        {
            Text            = "MPP Pipeline - Setup";
            Size            = new Size(600, 520);
            MinimumSize     = new Size(600, 520);
            MaximumSize     = new Size(600, 520);
            StartPosition   = FormStartPosition.CenterScreen;
            BackColor       = BgLight;
            Font            = new Font("Segoe UI", 9f);
            FormBorderStyle = FormBorderStyle.FixedDialog;
            MaximizeBox     = false;

            // Header
            pnlHeader = new Panel { Dock = DockStyle.Top, Height = 72, BackColor = Navy };
            lblTitle = new Label {
                Text = "  MPP Pipeline", ForeColor = Color.White,
                Font = new Font("Segoe UI", 18f, FontStyle.Bold),
                AutoSize = false, Left = 0, Top = 8, Width = 600, Height = 36,
                TextAlign = ContentAlignment.MiddleLeft
            };
            lblSubtitle = new Label {
                Text = "  Filter  -  Preview  -  Export MS Project files to XML",
                ForeColor = Color.FromArgb(180, 210, 240),
                Font = new Font("Segoe UI", 9.5f),
                AutoSize = false, Left = 0, Top = 44, Width = 600, Height = 24,
                TextAlign = ContentAlignment.MiddleLeft
            };
            pnlHeader.Controls.Add(lblTitle);
            pnlHeader.Controls.Add(lblSubtitle);
            Controls.Add(pnlHeader);

            // Body
            pnlBody = new Panel { Left = 0, Top = 72, Width = 600, Height = 404, BackColor = BgLight };

            lblDirLabel = new Label {
                Text = "Install Location:", Left = 24, Top = 32, Width = 200, Height = 22,
                TextAlign = ContentAlignment.MiddleLeft,
                ForeColor = Gray, Font = new Font("Segoe UI", 9f, FontStyle.Bold)
            };
            tbInstallDir = new TextBox {
                Left = 24, Top = 56, Width = 450, Height = 24,
                Text = installDir, Font = new Font("Segoe UI", 9f)
            };
            tbInstallDir.TextChanged += delegate { installDir = tbInstallDir.Text.Trim(); };

            btnBrowse = new Button {
                Text = "Browse...", Left = 482, Top = 54, Width = 92, Height = 28,
                FlatStyle = FlatStyle.Flat, Font = new Font("Segoe UI", 9f)
            };
            btnBrowse.FlatAppearance.BorderColor = Color.FromArgb(180, 180, 200);
            btnBrowse.Click += BtnBrowse_Click;

            var lblWhat = new Label {
                Text = "What this installer will do:", Left = 24, Top = 100, Width = 560, Height = 20,
                ForeColor = Gray, Font = new Font("Segoe UI", 9f, FontStyle.Bold)
            };
            pnlBody.Controls.Add(lblWhat);

            string[] steps = {
                "  + Extract bundled PS2EXE compiler (no internet required)",
                "  + Compile MPP-Pipeline.exe into your chosen install folder",
                "  + Create a Desktop shortcut",
                "  + Create a Start Menu entry",
                "  + Register in Windows Add / Remove Programs"
            };
            int top = 124;
            foreach (string step in steps) {
                var lbl = new Label {
                    Text = step, Left = 24, Top = top, Width = 560, Height = 20,
                    ForeColor = Color.FromArgb(60, 80, 60), Font = new Font("Segoe UI", 9f)
                };
                pnlBody.Controls.Add(lbl);
                top += 20;
            }

            pgBar = new ProgressBar {
                Left = 24, Top = 240, Width = 556, Height = 18,
                Minimum = 0, Maximum = 100, Visible = false, Style = ProgressBarStyle.Continuous
            };
            lblStatus = new Label {
                Text = "", Left = 24, Top = 264, Width = 556, Height = 22,
                ForeColor = Navy, Font = new Font("Segoe UI", 9f, FontStyle.Bold), Visible = false
            };
            lblDetail = new Label {
                Text = "", Left = 24, Top = 290, Width = 556, Height = 20,
                ForeColor = Gray, Font = new Font("Segoe UI", 8.5f), Visible = false
            };

            btnInstall = new Button {
                Text = "  Install Now  >", Left = 412, Top = 354, Width = 164, Height = 36,
                FlatStyle = FlatStyle.Flat, BackColor = Green, ForeColor = Color.White,
                Font = new Font("Segoe UI", 10.5f, FontStyle.Bold)
            };
            btnInstall.FlatAppearance.BorderSize = 0;
            btnInstall.Click += BtnInstall_Click;

            pnlBody.Controls.Add(lblDirLabel);
            pnlBody.Controls.Add(tbInstallDir);
            pnlBody.Controls.Add(btnBrowse);
            pnlBody.Controls.Add(pgBar);
            pnlBody.Controls.Add(lblStatus);
            pnlBody.Controls.Add(lblDetail);
            pnlBody.Controls.Add(btnInstall);
            Controls.Add(pnlBody);

            // Footer
            pnlFooter = new Panel { Left = 0, Top = 476, Width = 600, Height = 44,
                BackColor = Color.FromArgb(220, 225, 235) };
            lblFooter = new Label {
                Text = "SCI  -  MPP Pipeline v1.0", Left = 12, Top = 0, Width = 500, Height = 44,
                ForeColor = Color.FromArgb(120, 130, 150), Font = new Font("Segoe UI", 8.5f),
                TextAlign = ContentAlignment.MiddleLeft
            };
            pnlFooter.Controls.Add(lblFooter);
            Controls.Add(pnlFooter);
        }

        void BtnBrowse_Click(object sender, EventArgs e)
        {
            FolderBrowserDialog dlg = new FolderBrowserDialog();
            dlg.Description = "Choose install location for MPP Pipeline";
            dlg.SelectedPath = installDir;
            dlg.ShowNewFolderButton = true;
            if (dlg.ShowDialog() == DialogResult.OK) {
                installDir = dlg.SelectedPath;
                tbInstallDir.Text = installDir;
            }
        }

        void BtnInstall_Click(object sender, EventArgs e)
        {
            if (installing) return;
            if (string.IsNullOrEmpty(installDir)) {
                MessageBox.Show("Please choose an install location.", "Setup",
                    MessageBoxButtons.OK, MessageBoxIcon.Warning);
                return;
            }
            installing = true;
            btnInstall.Enabled   = false;
            btnBrowse.Enabled    = false;
            tbInstallDir.Enabled = false;
            pgBar.Visible        = true;
            lblStatus.Visible    = true;
            lblDetail.Visible    = true;
            btnInstall.Text      = "Installing...";
            Thread t = new Thread(RunInstall);
            t.IsBackground = true;
            t.Start();
        }

        void SetStatus(string status, string detail, int progress)
        {
            if (InvokeRequired) {
                Invoke(new Action<string, string, int>(SetStatus), status, detail, progress);
                return;
            }
            lblStatus.Text = status;
            lblDetail.Text = detail;
            if (progress >= 0) pgBar.Value = Math.Min(100, progress);
            Application.DoEvents();
        }

        void RunInstall()
        {
            string exePath    = Path.Combine(installDir, "MPP-Pipeline.exe");
            string uninstPath = Path.Combine(installDir, "Uninstall.exe");
            string tempPs1    = Path.Combine(Path.GetTempPath(),
                "MPP-" + Guid.NewGuid().ToString("N").Substring(0, 8) + ".ps1");
            string ps2exeDir  = Path.Combine(Path.GetTempPath(),
                "ps2exe-" + Guid.NewGuid().ToString("N").Substring(0, 8));
            try {
                // Step 1 - create install dir
                SetStatus("Step 1 of 4 - Preparing install folder...", installDir, 5);
                Directory.CreateDirectory(installDir);

                // Always recompile to ensure latest version is installed
                if (true) {
                    // Step 2 - extract app PS1 and PS2EXE module to temp
                    SetStatus("Step 2 of 4 - Extracting files...", "", 15);

                    // Write app PS1
                    byte[] appBytes = Convert.FromBase64String(Program.APP_SOURCE_B64);
                    File.WriteAllBytes(tempPs1, appBytes);

                    // Extract PS2EXE module files to temp folder
                    Directory.CreateDirectory(ps2exeDir);
                    File.WriteAllBytes(Path.Combine(ps2exeDir, "ps2exe.ps1"),
                        Convert.FromBase64String(Program.PS2EXE_PS1_B64));
                    File.WriteAllBytes(Path.Combine(ps2exeDir, "ps2exe.psd1"),
                        Convert.FromBase64String(Program.PS2EXE_PSD1_B64));
                    File.WriteAllBytes(Path.Combine(ps2exeDir, "ps2exe.psm1"),
                        Convert.FromBase64String(Program.PS2EXE_PSM1_B64));
                    File.WriteAllBytes(Path.Combine(ps2exeDir, "Win-PS2EXE.exe"),
                        Convert.FromBase64String(Program.PS2EXE_WINEXE_B64));

                    SetStatus("Step 2 of 4 - Files extracted.", "", 30);

                    // Step 3 - compile using the local PS2EXE copy
                    SetStatus("Step 3 of 4 - Compiling MPP-Pipeline.exe...",
                              "This takes about 20-30 seconds...", 40);

                    System.Text.StringBuilder compScript = new System.Text.StringBuilder();
                    compScript.AppendLine("Import-Module '" + ps2exeDir + "\\ps2exe.psd1' -Force");
                    compScript.AppendLine("$params = @{");
                    compScript.AppendLine("  InputFile   = '" + tempPs1  + "'");
                    compScript.AppendLine("  OutputFile  = '" + exePath  + "'");
                    compScript.AppendLine("  NoConsole   = $true");
                    compScript.AppendLine("  Title       = 'MPP Pipeline'");
                    compScript.AppendLine("  Product     = 'MPP Pipeline'");
                    compScript.AppendLine("  Description = 'Filter, Preview and Export MS Project MPP files to XML'");
                    compScript.AppendLine("  Company     = 'SCI'");
                    compScript.AppendLine("  Version     = '1.0.0.0'");
                    compScript.AppendLine("}");
                    compScript.AppendLine("Invoke-ps2exe @params");

                    string err2;
                    string r2 = RunPS(compScript.ToString(), out err2);
                    if (r2 == null || !File.Exists(exePath))
                        throw new Exception("Compilation failed:\n" + err2);

                    // Cleanup temp files
                    try { File.Delete(tempPs1); } catch {}
                    try { Directory.Delete(ps2exeDir, true); } catch {}
                }

                SetStatus("Step 4 of 4 - Finalising...", "Creating shortcuts and registry entries...", 88);

                // Desktop shortcut
                string desk = Environment.GetFolderPath(Environment.SpecialFolder.DesktopDirectory);
                CreateShortcut(Path.Combine(desk, "MPP Pipeline.lnk"), exePath,
                               "MPP Pipeline - Filter, Preview and Export MPP files");

                // Start Menu
                string smDir = Path.Combine(
                    Environment.GetFolderPath(Environment.SpecialFolder.Programs),
                    "MPP Pipeline");
                Directory.CreateDirectory(smDir);
                CreateShortcut(Path.Combine(smDir, "MPP Pipeline.lnk"), exePath,
                               "MPP Pipeline - Filter, Preview and Export MPP files");
                CreateShortcut(Path.Combine(smDir, "Uninstall MPP Pipeline.lnk"),
                               uninstPath, "Uninstall MPP Pipeline");

                // Write uninstaller
                WriteUninstaller(uninstPath, installDir);

                // Registry
                WriteRegistry(installDir, exePath, uninstPath);

                SetStatus("", "", 100);
                Invoke(new Action<string>(ShowFinished), exePath);
            }
            catch (Exception ex) {
                try { File.Delete(tempPs1); } catch {}
                try { Directory.Delete(ps2exeDir, true); } catch {}
                Invoke(new Action<string>(ShowError), ex.Message);
            }
        }

        string RunPS(string script, out string stderr)
        {
            string tmpScript = Path.Combine(Path.GetTempPath(),
                "mppsetup-" + Guid.NewGuid().ToString("N").Substring(0, 8) + ".ps1");
            try {
                File.WriteAllText(tmpScript, script, Encoding.UTF8);
                ProcessStartInfo psi = new ProcessStartInfo();
                psi.FileName               = "powershell.exe";
                psi.Arguments              = "-NonInteractive -WindowStyle Hidden -ExecutionPolicy Bypass -File \"" + tmpScript + "\"";
                psi.UseShellExecute        = false;
                psi.RedirectStandardOutput = true;
                psi.RedirectStandardError  = true;
                psi.CreateNoWindow         = true;
                Process p = Process.Start(psi);
                string stdout = p.StandardOutput.ReadToEnd();
                stderr        = p.StandardError.ReadToEnd();
                p.WaitForExit();
                try { File.Delete(tmpScript); } catch {}
                return p.ExitCode == 0 ? stdout : null;
            }
            catch (Exception ex) {
                try { File.Delete(tmpScript); } catch {}
                stderr = ex.Message;
                return null;
            }
        }

        void CreateShortcut(string lnkPath, string targetPath, string description)
        {
            string cmd =
                "$s=(New-Object -COM WScript.Shell).CreateShortcut('" + lnkPath.Replace("'","''") + "');" +
                "$s.TargetPath='" + targetPath.Replace("'","''") + "';" +
                "$s.Description='" + description.Replace("'","''") + "';" +
                "$s.Save()";
            string err;
            RunPS(cmd, out err);
        }

        void WriteRegistry(string dir, string exePath, string uninstPath)
        {
            string cmd =
                "$k='HKCU:\\Software\\Microsoft\\Windows\\CurrentVersion\\Uninstall\\MPPPipeline';" +
                "New-Item -Path $k -Force | Out-Null;" +
                "Set-ItemProperty -Path $k -Name DisplayName     -Value 'MPP Pipeline';" +
                "Set-ItemProperty -Path $k -Name DisplayVersion  -Value '1.0.0';" +
                "Set-ItemProperty -Path $k -Name Publisher       -Value 'SCI';" +
                "Set-ItemProperty -Path $k -Name InstallLocation -Value '" + dir.Replace("'","''") + "';" +
                "Set-ItemProperty -Path $k -Name UninstallString -Value '" + uninstPath.Replace("'","''") + "';" +
                "Set-ItemProperty -Path $k -Name NoModify        -Value 1 -Type DWord;" +
                "Set-ItemProperty -Path $k -Name NoRepair        -Value 1 -Type DWord;";
            string err;
            RunPS(cmd, out err);
        }

        void WriteUninstaller(string uninstPath, string dir)
        {
            string cscPath = FindCsc();
            if (cscPath == null) return;
            string src =
                "using System; using System.IO; using System.Windows.Forms; using System.Diagnostics;" +
                "class U{[STAThread]static void Main(){" +
                "if(MessageBox.Show(\"Remove MPP Pipeline?\",\"Uninstall\"," +
                "MessageBoxButtons.YesNo,MessageBoxIcon.Question)!=DialogResult.Yes)return;" +
                "try{" +
                "string d=@\"" + dir.Replace("\"","\"\"\"") + "\";" +
                "string e=Path.Combine(d,\"MPP-Pipeline.exe\");" +
                "if(File.Exists(e))File.Delete(e);" +
                "string desk=Environment.GetFolderPath(Environment.SpecialFolder.DesktopDirectory);" +
                "string lnk=Path.Combine(desk,\"MPP Pipeline.lnk\");" +
                "if(File.Exists(lnk))File.Delete(lnk);" +
                "string sm=Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.Programs),\"MPP Pipeline\");" +
                "if(Directory.Exists(sm))Directory.Delete(sm,true);" +
                "Process rp=new Process();" +
                "rp.StartInfo=new ProcessStartInfo(\"powershell.exe\"," +
                "\"-NonInteractive -WindowStyle Hidden -ExecutionPolicy Bypass -Command \" +" +
                "\"\\\"\"Remove-Item -Path HKLM:\\\\\\\\Software\\\\\\\\Microsoft\\\\\\\\Windows\\\\\\\\CurrentVersion\\\\\\\\Uninstall\\\\\\\\MPPPipeline -Recurse -Force -ErrorAction SilentlyContinue\\\"\"\");" +
                "rp.StartInfo.WindowStyle=ProcessWindowStyle.Hidden;rp.Start();rp.WaitForExit();" +
                "string u=Assembly.GetExecutingAssembly().Location;" +
                "Process.Start(new ProcessStartInfo(\"cmd.exe\",\"/C choice /T 2 /D Y /N && del \\\"\"+u+\"\\\" && rmdir /Q \\\"\"+d+\"\\\"\"){WindowStyle=ProcessWindowStyle.Hidden});" +
                "MessageBox.Show(\"MPP Pipeline has been uninstalled.\",\"Done\",MessageBoxButtons.OK,MessageBoxIcon.Information);" +
                "}catch(Exception ex){MessageBox.Show(\"Uninstall error: \"+ex.Message,\"Error\",MessageBoxButtons.OK,MessageBoxIcon.Error);}}}";

            string tempSrc = Path.Combine(Path.GetTempPath(),
                "MPPUninst-" + Guid.NewGuid().ToString("N").Substring(0, 6) + ".cs");
            File.WriteAllText(tempSrc, src, Encoding.UTF8);
            ProcessStartInfo psi2 = new ProcessStartInfo();
            psi2.FileName               = cscPath;
            psi2.Arguments              = "/nologo /target:winexe /r:System.Windows.Forms.dll /out:\"" + uninstPath + "\" \"" + tempSrc + "\"";
            psi2.UseShellExecute        = false;
            psi2.RedirectStandardOutput = true;
            psi2.RedirectStandardError  = true;
            psi2.CreateNoWindow         = true;
            Process pc = Process.Start(psi2);
            pc.WaitForExit();
            try { File.Delete(tempSrc); } catch {}
        }

        string FindCsc()
        {
            string[] paths = {
                @"C:\Windows\Microsoft.NET\Framework64\v4.0.30319\csc.exe",
                @"C:\Windows\Microsoft.NET\Framework\v4.0.30319\csc.exe",
                @"C:\Windows\Microsoft.NET\Framework64\v3.5\csc.exe",
                @"C:\Windows\Microsoft.NET\Framework\v3.5\csc.exe"
            };
            foreach (string p in paths)
                if (File.Exists(p)) return p;
            return null;
        }

        void ShowFinished(string exePath)
        {
            pnlBody.Controls.Clear();
            var lblDone = new Label {
                Text = "Installation Complete", Left = 24, Top = 40, Width = 530, Height = 36,
                ForeColor = Green, Font = new Font("Segoe UI", 14f, FontStyle.Bold),
                TextAlign = ContentAlignment.MiddleLeft
            };
            var lblInfo = new Label {
                Text = "MPP Pipeline has been installed successfully.\n" +
                       "A shortcut has been added to your Desktop and Start Menu.",
                Left = 24, Top = 84, Width = 530, Height = 44,
                ForeColor = Gray, Font = new Font("Segoe UI", 9.5f)
            };
            CheckBox chkLaunch = new CheckBox {
                Text = "Launch MPP Pipeline now",
                Left = 24, Top = 144, Width = 280, Height = 24,
                Checked = true, Font = new Font("Segoe UI", 9.5f)
            };
            Button btnFinish = new Button {
                Text = "  Finish", Left = 412, Top = 248, Width = 164, Height = 36,
                FlatStyle = FlatStyle.Flat, BackColor = Navy, ForeColor = Color.White,
                Font = new Font("Segoe UI", 10.5f, FontStyle.Bold)
            };
            btnFinish.FlatAppearance.BorderSize = 0;
            btnFinish.Click += delegate {
                if (chkLaunch.Checked) { try { Process.Start(exePath); } catch {} }
                Application.Exit();
            };
            pnlBody.Controls.Add(lblDone);
            pnlBody.Controls.Add(lblInfo);
            pnlBody.Controls.Add(chkLaunch);
            pnlBody.Controls.Add(btnFinish);
        }

        void ShowError(string message)
        {
            installing = false;
            pgBar.Visible = false; lblStatus.Visible = false; lblDetail.Visible = false;
            btnInstall.Enabled = true; btnBrowse.Enabled = true; tbInstallDir.Enabled = true;
            btnInstall.Text = "  Retry  >";
            MessageBox.Show("Installation failed:\n\n" + message,
                "Setup Error", MessageBoxButtons.OK, MessageBoxIcon.Error);
        }
    }
}
